import scala.collection.mutable

def solve(nums: Array[Long], k: Long): Long = {
    var prefixSum = 0L
    val modMap = mutable.Map[Long, Int](0L -> -1)
    val n = nums.length
    val dp = Array.fill(n)(0L)
    val totalSum = nums.sum
    var maxDeletable = 0L

    for (i <- 0 until n) {
        prefixSum += nums(i)
        val mod = prefixSum % k
        if (modMap.contains(mod)) {
            val j = modMap(mod)
            val currentSum = if (j != -1) dp(j) else 0L
            dp(i) = currentSum + (prefixSum - (if (j == -1) 0L else dp(j))) / k * k
        } else {
            dp(i) = if (prefixSum % k == 0) (prefixSum / k) * k else 0L
        }
        modMap(mod) = i
        if (dp(i) > maxDeletable) maxDeletable = dp(i)
    }

    totalSum - maxDeletable
}
